#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
struct node{long long s,dd;}h[N];
long long n,a[N],num,id[N],k,sum,ans[N];
bool cmp(node n1,node n2){return n1.s<n2.s;}
int lst(int x){if(x==1)return n;return x-1;}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];num+=a[i];
    }
    num/=n;
    for(int i=1;i<=n;i++)
        h[i].s=h[i-1].s+a[i]-num,h[i].dd=i;
    sort(h+1,h+n+1,cmp);
    k=(n+1)/2;
    for(int i=1;i<=n;i++)
        sum+=abs(h[i].s-h[k].s);
    //cout<<k<<" ";
    k=h[k].dd+1;
    //cout<<k<<"\n";
    for(int i=1;i<=n-k+1;i++)id[i]=k+i-1;
    for(int i=n-k+2;i<=n;i++)id[i]=i-n+k-1;
    for(int i=1;i<=n;i++)
        ans[id[i]]=a[id[i]]+ans[id[i-1]]-num;
    cout<<sum<<"\n";
    for(int i=1;i<=n;i++)cout<<-ans[lst(i)]<<" "<<ans[i]<<"\n";
    return 0;
}
